# Silk Background Animation

A full-screen canvas background that generates an animated silk-like texture using a procedural noise pattern with sinusoidal distortion. The purple-gray silk shimmers and flows continuously. Includes a fade-in entrance for overlaid text content.

## Use when
- Building a dark luxury or fashion brand landing page with an animated textile background.
- Creating an artistic hero section with a shimmering, flowing canvas texture.
- Adding a high-end visual identity to a portfolio or creative agency page.
- Showcasing a product with an immersive silk-fabric animated backdrop.

## Stack
- Framework: react
- Libraries: (none)
- Requires: tailwind, shadcn

## Install
```bash
# no additional packages required
```

## Component — silk-background-animation.tsx
```tsx
'use client';

import React, { useEffect, useRef, useState } from 'react';

export const Component = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationRef = useRef<number>();
  const [isLoaded, setIsLoaded] = useState(false);

  useEffect(() => {
    const timer = setTimeout(() => setIsLoaded(true), 300);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let time = 0;
    const speed = 0.02;
    const scale = 2;
    const noiseIntensity = 0.8;

    const resizeCanvas = () => { canvas.width = window.innerWidth; canvas.height = window.innerHeight; };
    resizeCanvas();
    window.addEventListener('resize', resizeCanvas);

    const noise = (x: number, y: number) => {
      const G = 2.71828;
      const rx = G * Math.sin(G * x); const ry = G * Math.sin(G * y);
      return (rx * ry * (1 + x)) % 1;
    };

    const animate = () => {
      const { width, height } = canvas;
      const gradient = ctx.createLinearGradient(0, 0, width, height);
      gradient.addColorStop(0, '#1a1a1a'); gradient.addColorStop(0.5, '#2a2a2a'); gradient.addColorStop(1, '#1a1a1a');
      ctx.fillStyle = gradient; ctx.fillRect(0, 0, width, height);
      const imageData = ctx.createImageData(width, height);
      const data = imageData.data;
      for (let x = 0; x < width; x += 2) {
        for (let y = 0; y < height; y += 2) {
          const u = (x / width) * scale; const v = (y / height) * scale;
          const tOffset = speed * time;
          const tex_x = u; const tex_y = v + 0.03 * Math.sin(8.0 * tex_x - tOffset);
          const pattern = 0.6 + 0.4 * Math.sin(5.0 * (tex_x + tex_y + Math.cos(3.0 * tex_x + 5.0 * tex_y) + 0.02 * tOffset) + Math.sin(20.0 * (tex_x + tex_y - 0.1 * tOffset)));
          const rnd = noise(x, y);
          const intensity = Math.max(0, pattern - rnd / 15.0 * noiseIntensity);
          const r = Math.floor(123 * intensity); const g = Math.floor(116 * intensity); const b = Math.floor(129 * intensity);
          const index = (y * width + x) * 4;
          if (index < data.length) { data[index] = r; data[index + 1] = g; data[index + 2] = b; data[index + 3] = 255; }
        }
      }
      ctx.putImageData(imageData, 0, 0);
      const overlayGradient = ctx.createRadialGradient(width / 2, height / 2, 0, width / 2, height / 2, Math.max(width, height) / 2);
      overlayGradient.addColorStop(0, 'rgba(0,0,0,0.1)'); overlayGradient.addColorStop(1, 'rgba(0,0,0,0.4)');
      ctx.fillStyle = overlayGradient; ctx.fillRect(0, 0, width, height);
      time += 1;
      animationRef.current = requestAnimationFrame(animate);
    };

    animate();

    return () => {
      window.removeEventListener('resize', resizeCanvas);
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, []);

  return (
    <div className="relative h-screen w-full overflow-hidden bg-black">
      <canvas ref={canvasRef} className="absolute top-0 left-0 w-full h-full z-0" />
      <div className="absolute inset-0 z-10 bg-gradient-to-b from-black/30 via-transparent to-black/50" />
      <div className="relative z-20 flex h-full items-center justify-center">
        <div className="text-center px-8">
          <h1
            className={`text-6xl sm:text-8xl md:text-9xl font-light tracking-[-0.05em] leading-none text-white mix-blend-difference opacity-0 ${isLoaded ? 'animate-[fadeInUp_1s_ease-out_forwards]' : ''}`}
            style={{ textShadow: '0 0 40px rgba(255,255,255,0.1)' }}
          >
            silk
          </h1>
          <div className={`mt-8 text-lg md:text-xl font-extralight tracking-[0.2em] uppercase text-gray-300/80 opacity-0 ${isLoaded ? 'animate-[fadeInUp_1s_ease-out_0.3s_forwards]' : ''}`}>
            flowing • texture • art
          </div>
        </div>
      </div>
    </div>
  );
};
```

## Demo
```tsx
import { Component } from "@/components/ui/silk-background-animation";

const DemoOne = () => {
  return <Component />;
};

export { DemoOne };
```

## Notes
- The canvas renders at native `window.innerWidth × window.innerHeight` with every-other-pixel rendering (`x += 2, y += 2`) for performance — full resolution would be 4× slower.
- The original uses `<style>` tags for `fadeInUp` keyframes; in Tailwind 4 or with JIT, add `animate-[fadeInUp_1s_ease-out_forwards]` or define the keyframe in `tailwind.config.js`.
